\n\n    if (minMax) {\n      Util.scaleMinMax(transform, minMax);\n      for (let k = 0, kk = buffer.length; k < kk; ) {\n        switch (buffer[k++]) {\n          case DrawOPS.moveTo:\n          case DrawOPS.lineTo:\n            Util.applyTransform(buffer, transform, k);\n            k += 2;\n            break;\n          case DrawOPS.curveTo:\n            Util.applyTransformToBezier(buffer, transform, k);\n            k += 6;\n            break;\n        }\n      }\n    }\n    // Replace queue items.\n    fnArray.splice(iFirstSave, 4, OPS.constructPath);\n    argsArray.splice(iFirstSave, 4, args);\n\n    return iFirstSave + 1;\n  }\n);\n\nclass NullOptimizer {\n  constructor(queue) {\n    this.queue = queue;\n  }\n\n  _optimize() {}\n\n  push(fn, args) {\n    this.queue.fnArray.push(fn);\n    this.queue.argsArray.push(args);\n    this._optimize();\n  }\n\n  flush() {}\n\n  reset() {}\n}\n\nclass QueueOptimizer extends NullOptimizer {\n  constructor(queue) {\n    super(queue);\n    this.state = null;\n    this.context = {\n      iCurr: 0,\n      fnArray: queue.fnArray,\n      argsArray: queue.argsArray,\n      isOffscreenCanvasSupported: OperatorList.isOffscreenCanvasSupported,\n    };\n    this.match = null;\n    this.lastProcessed = 0;\n  }\n\n  _optimize() {\n    // Process new fnArray item(s) chunk.\n    const fnArray = this.queue.fnArray;\n    let i = this.lastProcessed,\n      ii = fnArray.length;\n    let state = this.state;\n    let match = this.match;\n    if (!state && !match && i + 1 === ii && !InitialState[fnArray[i]]) {\n      // Micro-optimization for the common case: last item is not\n      // optimizable, just skipping it.\n      this.lastProcessed = ii;\n      return;\n    }\n\n    const context = this.context;\n    while (i < ii) {\n      if (match) {\n        // Already find a block of potentially optimizable items, iterating...\n        const iterate = (0, match.iterateFn)(context, i);\n        if (iterate) {\n          i++;\n          continue;